

const subscribe = (retrying = 0, topic) => {
  console.log('subscribing in...', retrying)
  setTimeout(() => {  

    const observableGenerator = observableGenerators[topic]
    const callback = callbacks[topic]    
    const observable = observableGenerator(topic)

    subscriptions[topic] = observable.subscribe({
      next: (eventData) => {
        retrying = 0
        console.log('eventData', eventData)
        callback(eventData)
      },
      error: (data) => {
        console.error('subscribe connection errors', data)
        const { errors } = data
        if (errors && errors.find(error => error.message === 'Network Error')) {
          if (retrying === 0) {
            retrying = 50
          }
          subscribe(retrying * 2, topic)
        }
      },
      complete: (data) => console.log('completed', data)
    })
  }, retrying)
}

const disconnect = (topic) => {
  console.log(`disconnect ${topic}:`, subscriptions[topic])
  if (subscriptions[topic] && typeof subscriptions[topic].unsubscribe === 'function') {
    subscriptions[topic].unsubscribe()
    delete callbacks[topic]
    delete subscriptions[topic]
    delete observableGenerators[topic]
  }
}

const connect = (topic, observableGenerator, callback) => {
  console.log('observableGenerator', observableGenerator)
  console.log('callback', callback)



  if (!subscriptions[topic] || subscriptions[topic].closed) {
    disconnect(topic)

    callbacks[topic] = callback
    observableGenerators[topic] = observableGenerator
    subscribe(0, topic)
  }
}


const subscriber = {
  connect,
  disconnect,
}

const callbacks = {}
const subscriptions = {}
const observableGenerators= {}

export default subscriber